func (m organizationMods) WithParentsCascading() OrganizationMod {
	return OrganizationModFunc(func(ctx context.Context, o *OrganizationTemplate) {
		if isDone, _ := organizationWithParentsCascadingCtx.Value(ctx); isDone {
			return
		}
		ctx = organizationWithParentsCascadingCtx.WithValue(ctx, true)
		{

			related := o.f.NewOrganizationContactWithContext(ctx, OrganizationContactMods.WithParentsCascading())
			m.WithOrganizationContact(related).Apply(ctx, o)
		}
		{

			related := o.f.NewOrganizationWorkHourWithContext(ctx, OrganizationWorkHourMods.WithParentsCascading())
			m.WithOrganizationWorkHour(related).Apply(ctx, o)
		}
	})
}

